import React from 'react';
import { Link } from 'react-router-dom';
import { ItemEntity } from '../../../item-entity/ItemEntity';
import { IdentityInterface } from '../../../../store/reducers/ids-reducer';
import { EGOInterface } from '../../../../store/reducers/ego-reducer';

export const useEntityHelpers = (t: any, i18n: any, egos: EGOInterface[], ids: IdentityInterface[]) => {
    // 1. Добавляем параметр index (по умолчанию генерируем случайную строку для надежности)
    const newEntityLinkFunc = (fullMatch: string, index: number | string = Math.random().toString(36).slice(2, 9)) => {
        const isEgos = fullMatch.startsWith('egos_');
        const idRaw = fullMatch.match(/\d+/)?.[0];
        const imgUrl = isEgos ? `ego_${idRaw}` : `id_${idRaw}`;
        
        const item = isEgos 
            ? egos?.find(e => e.imgUrl === imgUrl) 
            : ids?.find(i => i.imgUrl === imgUrl);
        
        if (!item) return fullMatch;

        const baseName = i18n.language === 'ru' ? item.nameRU : item.nameEN;
        const sinnerKey = item.sinner?.toLowerCase().replace(/\s+/g, '');
        const translatedSinner = t(`sinners.${sinnerKey}`);
        const name = `[${baseName}] ${translatedSinner}`;
        const path = isEgos ? 'ego' : 'identities';
        
        // 2. Делаем ключ уникальным: "ego_12-0", "ego_12-1" и т.д.
        return (
            <Link key={`${imgUrl}-${index}`} to={`/limbus/${i18n.language}/${path}/${imgUrl}`} className="entity-link">
                <img className="entity-icon" src={`${process.env.PUBLIC_URL}/images/${path}/${imgUrl}.webp`} alt={imgUrl} />
                {name}
            </Link>
        );
    };

    const egoFunc = (value: string, index: number | string = Math.random().toString(36).slice(2, 9)) => {
        const item = egos?.find(e => e.imgUrl === value) || ids?.find(i => i.imgUrl === value);
        if (!item) return null;
        
        // Также делаем ключ уникальным здесь
        return (
            <span key={`${item.imgUrl}-${index}`} style={{ display: "inline-block" }}>
                <ItemEntity entity={item} />
            </span>
        );
    };

    return { newEntityLinkFunc, egoFunc };
};
