import React, { useState, useMemo, useEffect } from 'react'; 
import { supabase } from '../../../tools/supabaseClient';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useDispatch } from 'react-redux';
import { IdentityInterface } from '../../../store/reducers/ids-reducer';
import { setMobileModalTrigger } from '../../../store/reducers/mobile-modal-reducer';
import { StatusesInterface } from '../../../store/reducers/statuses-reducer';
import { getStatusesEntityList } from '../../../tools/getStatusesEntityList';
import { TooltipMobile } from '../../tooltip-mobile/TooltipMobile';
import { SkillCoinDescription } from "../../guides/text-formatter/SkillCoinDescription";
import "./EntityFullInfoIdentity.css";
import { useTypedSelector } from '../../../hooks/useTypedSelector';
import { useEntityRating } from '../../../hooks/useEntityRating';
import { useReviewerAccess } from '../../../hooks/useReviewerAccess';

interface IEntityFullInfoProps {
    identity: IdentityInterface;
    maxLvlIdentity: number;
    statusUnik?: string;
}

interface AdminField {
    label: string;
    key: string;
    type: 'text' | 'number';
}

interface AdminTab {
    id: string;
    title: string;
    fields: AdminField[];
}

const ADMIN_TABS: AdminTab[] = [
  {
    id: 'general',
    title: 'Общая информация',
    fields: [
      { label: 'Sinner', key: 'sinner', type: 'text' },
      { label: 'Name RU', key: 'nameRU', type: 'text' },
      { label: 'Name EN', key: 'nameEN', type: 'text' },
      { label: 'Rarity', key: 'rarity', type: 'text' },
      { label: 'Season', key: 'season', type: 'text' },
      { label: 'Release Date', key: 'releaseDate', type: 'text' },
      { label: 'Is New', key: 'isNew', type: 'text' },
      { label: 'Identity Tier (Rank)', key: 'idTier', type: 'text' },
      { label: 'Status Unik', key: 'statusUnik', type: 'text' },
      { label: 'Traits', key: 'traits', type: 'text' }
    ]
  },
  {
    id: 'stats',
    title: 'Характеристики и Резисты',
    fields: [
      { label: 'HP', key: 'hp', type: 'number' },
      { label: 'Defense', key: 'defense', type: 'number' },
      { label: 'Speed', key: 'speed', type: 'text' },
      { label: 'Stagger Points', key: 'hpStun', type: 'text' },
      { label: 'Slash', key: 'slash', type: 'text' },
      { label: 'Pierce', key: 'pierce', type: 'text' },
      { label: 'Blunt', key: 'blunt', type: 'text' }
    ]
  },
  {
    id: 'skills_meta',
    title: 'Скиллы и Типы',
    fields: [
      { label: 'Skills Sin', key: 'skillsSin', type: 'text' },
      { label: 'Skills Dmg Type', key: 'skillsDmgType', type: 'text' },
      { label: 'Guard Sin', key: 'guardSin', type: 'text' },
      { label: 'Guard Type', key: 'guardType', type: 'text' },
      { label: 'Damage', key: 'damage', type: 'text' },
      { label: 'Skills Order', key: 'skillsOrder', type: 'text' },
      { label: 'Guard Tier', key: 'guardTier', type: 'text' }
    ]
  },
  {
    id: 'coins',
    title: 'Данные Монеток (Coins)',
    fields: [
      { label: 'Basic Coin (Базовые)', key: 'basicCoin', type: 'text' },
      { label: 'Growth Per Coin (Прирост)', key: 'growthPerCoin', type: 'text' },
      { label: 'Max Coin Value', key: 'maxCoinValue', type: 'text' },
      { label: 'Full Max Coin Value', key: 'fullMaxCoinValue', type: 'text' },
      { label: 'Count Coin (Кол-во монеток)', key: 'countCoin', type: 'text' },
      { label: 'Weight Coin (Вес)', key: 'weightCoin', type: 'text' },
      { label: 'Min Possible Dmg', key: 'minPossibleDmg', type: 'text' },
      { label: 'Max Possible Dmg', key: 'maxPossibleDmg', type: 'text' }
    ]
  },
  {
    id: 'descriptions',
    title: 'Тексты и Локализация',
    fields: [
      { label: 'Skill Names RU', key: 'nameSkillRU', type: 'text' },
      { label: 'Skill Names EN', key: 'nameSkillEN', type: 'text' },
      { label: 'Passive Names RU', key: 'namePassiveRU', type: 'text' },
      { label: 'Passive Names EN', key: 'namePassiveEN', type: 'text' },
      { label: 'Sin Passive 1', key: 'sinPassive1', type: 'text' },
      { label: 'Count Passive 1', key: 'countPassive1', type: 'text' },
      { label: 'Sin Passive 2', key: 'sinPassive2', type: 'text' },
      { label: 'Count Passive 2', key: 'countPassive2', type: 'text' },
      { label: 'Passive 1 Condition', key: 'passive1Condition', type: 'text' },
      { label: 'Passive 2 Condition', key: 'passive2Condition', type: 'text' },
      { label: 'Passive Tier', key: 'passiveTier', type: 'text' },
      { label: 'Syn EGO', key: 'synEGO', type: 'text' },
      { label: 'Sanity Info EN', key: 'sanityInfoEN', type: 'text' },
      { label: 'Sanity Info RU', key: 'sanityInfoRU', type: 'text' },
      { label: 'Passive 1 Description EN (Base)', key: 'descriptionPassive1EN', type: 'text' },
      { label: 'Passive 1 Description RU (Base)', key: 'descriptionPassive1RU', type: 'text' },
      { label: 'Passive 2 Description EN (Base)', key: 'descriptionPassive2EN', type: 'text' },
      { label: 'Passive 2 Description RU (Base)', key: 'descriptionPassive2RU', type: 'text' }
    ]
  },
  {
    id: 'coin_descriptions',
    title: 'Описания Монеток',
    fields: [
      { label: 'Coin RU 1', key: 'descriptionCoinRU1', type: 'text' },
      { label: 'Coin EN 1', key: 'descriptionCoinEN1', type: 'text' },
      { label: 'Coin RU 2', key: 'descriptionCoinRU2', type: 'text' },
      { label: 'Coin EN 2', key: 'descriptionCoinEN2', type: 'text' },
      { label: 'Coin RU 3', key: 'descriptionCoinRU3', type: 'text' },
      { label: 'Coin EN 3', key: 'descriptionCoinEN3', type: 'text' },
      { label: 'Coin RU 4', key: 'descriptionCoinRU4', type: 'text' },
      { label: 'Coin EN 4', key: 'descriptionCoinEN4', type: 'text' },
    ]
  },
  {
    id: 'passive_descriptions',
    title: 'Описания Пассивок (Uptie)',
    fields: [
      { label: 'Passive 1 EN (Uptie 1)', key: 'descriptionPassive1EN1', type: 'text' },
      { label: 'Passive 1 RU (Uptie 1)', key: 'descriptionPassive1RU1', type: 'text' },
      { label: 'Passive 2 EN (Uptie 1)', key: 'descriptionPassive2EN1', type: 'text' },
      { label: 'Passive 2 RU (Uptie 1)', key: 'descriptionPassive2RU1', type: 'text' },
      
      { label: 'Passive 1 EN (Uptie 2)', key: 'descriptionPassive1EN2', type: 'text' },
      { label: 'Passive 1 RU (Uptie 2)', key: 'descriptionPassive1RU2', type: 'text' },
      { label: 'Passive 2 EN (Uptie 2)', key: 'descriptionPassive2EN2', type: 'text' },
      { label: 'Passive 2 RU (Uptie 2)', key: 'descriptionPassive2RU2', type: 'text' },
      
      { label: 'Passive 1 EN (Uptie 3)', key: 'descriptionPassive1EN3', type: 'text' },
      { label: 'Passive 1 RU (Uptie 3)', key: 'descriptionPassive1RU3', type: 'text' },
      { label: 'Passive 2 EN (Uptie 3)', key: 'descriptionPassive2EN3', type: 'text' },
      { label: 'Passive 2 RU (Uptie 3)', key: 'descriptionPassive2RU3', type: 'text' }
    ]
  },
  {
    id: 'reviews',
    title: 'Обзоры и Гайды',
    fields: [
      { label: 'Review EN', key: 'reviewEN', type: 'text' },
      { label: 'Review RU', key: 'reviewRU', type: 'text' },
      { label: 'Guide EN', key: 'guideEN', type: 'text' },
      { label: 'Guide RU', key: 'guideRU', type: 'text' }
    ]
  }
];

const resMap: { [key: string]: string } = {
    'ineff': '[x0.5]',
    'normal': '[x1]',
    'fatal': '[x2]'
};

export const EntityFullInfoIdentity: React.FC<IEntityFullInfoProps> = ({ identity, maxLvlIdentity, statusUnik }) => {
    const { imgUrl, idTier, season, hp, hpStun, speed: speeds, defense, slash, pierce, blunt, rarity, sinner, releaseDate, synEGO } = identity;
    const tiers = String(idTier).split(",").map((t: string) => t.trim());
    const statuses = useQueryClient().getQueryData('statuses') as StatusesInterface[];
    const queryClient = useQueryClient();
    const rarityStyled = rarity.replaceAll("O", "Ø");
    const { t, i18n } = useTranslation();
    const dispatch = useDispatch();
    const { avgRating, handleVote, userVote } = useEntityRating(identity.imgUrl);
    const { selectedUptie } = useTypedSelector(s => s.uptieReducer);
    const RANK_MAP = ["NO","C", "B", "A", "S", "SS", "SSS"];
    const myRank = userVote !== null ? RANK_MAP[userVote] : null;
    
    const descriptionCoinKey = `descriptionCoin${i18n.language.toUpperCase()}${selectedUptie}` as keyof typeof identity;
    const descriptionCoin = identity[descriptionCoinKey] as string || '';

    const lang = i18n.language.toUpperCase();
    const descriptionPassive1 = identity[`descriptionPassive1${lang}` as keyof typeof identity] as string || '';
    const descriptionPassive2 = identity[`descriptionPassive2${lang}` as keyof typeof identity] as string || '';

    const { isReviewer } = useReviewerAccess();

    const status = useMemo(() => {
        return getStatusesEntityList([descriptionCoin, descriptionPassive1, descriptionPassive2]);
    }, [descriptionCoin, descriptionPassive1, descriptionPassive2]);

    const [imgID, setImgID] = useState('2');
    const isSwitched = imgID === '2';

    function updateStatusWithFuseStatuses(allStatuses: StatusesInterface[], status: { [key: string]: number }): { [key: string]: number } {
        const updatedStatus = { ...status };
        for (const id of Object.keys(status)) {
            const foundStatus = allStatuses.find(s => s.id === id);
            if (foundStatus && foundStatus.fuse_statuses) {
                const fuseId = foundStatus.fuse_statuses;
                if (!(fuseId in updatedStatus)) {
                    updatedStatus[fuseId] = 0;
                }
            }
        }
        return updatedStatus;
    }

    const isAdmin = false;
    
    const [isAdminPanelOpen, setIsAdminPanelOpen] = useState(false);
    const [activeTab, setActiveTab] = useState('general');
    const [adminFormData, setAdminFormData] = useState<any>({});

    const openAdminPanel = async () => {
        if (!isAdmin) return;
        
        try {
            const { data, error } = await supabase
                .from('ids')
                .select('*')
                .eq('imgUrl', identity.imgUrl)
                .single();

            if (error) throw error;

            const initialForm: any = data ? { ...data } : { ...identity };
            
            ADMIN_TABS.forEach((tab: AdminTab) => {
                tab.fields.forEach((f: AdminField) => {
                    if (Array.isArray(initialForm[f.key]) || (initialForm[f.key] && typeof initialForm[f.key] === 'object')) {
                        initialForm[f.key] = JSON.stringify(initialForm[f.key]);
                    }
                });
            });
            
            setAdminFormData(initialForm);
            setIsAdminPanelOpen(true);
        } catch (err: any) {
            alert('Ошибка загрузки сырых данных из базы: ' + err.message);
            
            const initialForm: any = { ...identity };
            ADMIN_TABS.forEach((tab: AdminTab) => {
                tab.fields.forEach((f: AdminField) => {
                    if (Array.isArray(initialForm[f.key])) {
                        initialForm[f.key] = JSON.stringify(initialForm[f.key]);
                    }
                });
            });
            setAdminFormData(initialForm);
            setIsAdminPanelOpen(true);
        }
    };

    const handleFormChange = (key: string, value: any) => {
        setAdminFormData((prev: any) => ({ ...prev, [key]: value }));
    };

    const saveAdminData = async () => {
        try {
            const dataToSave = { ...adminFormData };
            
            ADMIN_TABS.forEach((tab: AdminTab) => {
                tab.fields.forEach((f: AdminField) => {
                    if (f.type === 'number') {
                        dataToSave[f.key] = dataToSave[f.key] === '' ? 0 : Number(dataToSave[f.key]);
                    }
                    if (typeof dataToSave[f.key] === 'string' && (dataToSave[f.key].trim().startsWith('[') || dataToSave[f.key].trim().startsWith('{'))) {
                        try {
                            dataToSave[f.key] = JSON.parse(dataToSave[f.key]);
                        } catch (e) {
                            // Оставляем строкой
                        }
                    }
                });
            });

            const { error } = await supabase
                .from('ids')
                .update(dataToSave)
                .eq('imgUrl', identity.imgUrl);

            if (error) throw error;

            setIsAdminPanelOpen(false);
            queryClient.invalidateQueries('identities');
            alert('Данные успешно сохранены!');
        } catch (error: any) {
            alert('Ошибка сохранения: ' + error.message);
        }
    };

    const fuseStatuses = useMemo(() => {
        return updateStatusWithFuseStatuses(statuses, status);
    }, [statuses, status]);

    const filteredStatusKeys = useMemo(() => {
        if (!fuseStatuses) return [];
        if (!statusUnik) {
            return Object.keys(fuseStatuses).filter(s => fuseStatuses[s] > 0);
        }

        const [addPart, removePart] = statusUnik.split('|').map(part => part.trim());
        const statusesToAdd = addPart ? addPart.split('#').filter(s => s.trim()).map(s => s.trim().toLowerCase()) : [];
        const statusesToRemove = removePart ? removePart.split('#').filter(s => s.trim()).map(s => s.trim().toLowerCase()) : [];

        let filtered = Object.keys(fuseStatuses).filter(s => {
            const lower = s.toLowerCase();
            return !statusesToRemove.includes(lower) && fuseStatuses[s] > 0;
        });

        statusesToAdd.forEach(statusToAdd => {
            const foundStatus = statuses.find(st => st.id.toLowerCase() === statusToAdd);
            if (foundStatus) {
                const fullStatusId = foundStatus.id;
                if (!filtered.includes(fullStatusId)) filtered.push(fullStatusId);
            } else {
                if (!filtered.includes(statusToAdd)) filtered.push(statusToAdd);
            }
        });
        return filtered;
    }, [fuseStatuses, statusUnik, statuses]);

    const speed = useMemo(() => {
        if (Array.isArray(speeds)) {
            return speeds[selectedUptie - 1] || speeds[0];
        }
        return speeds;
    }, [speeds, selectedUptie]);

    const getImagePath = () => {
        let basePath = `${process.env.PUBLIC_URL}/images/identities-profiles/${imgUrl}`;
        if (imgID !== '2') return `${basePath}.${imgID}_profile.webp`;
        if ([1, 2].includes(selectedUptie)) return `${basePath}.1_profile.webp`;
        else if ([3, 4].includes(selectedUptie)) return `${basePath}.2_profile.webp`;
        return `${basePath}_profile.webp`;
    };

    const defLevelValue = maxLvlIdentity - (-defense);
    
    function excelToDate(excelDate: number) {
        const excelStartDate = new Date(1899, 11, 30);
        const millisecondsPerDay = 24 * 60 * 60 * 1000;
        return new Date(excelStartDate.getTime() + excelDate * millisecondsPerDay);
    }

    const formateDate = (date: number) => {
        const newDate = excelToDate(date);
        const month = `${newDate.getMonth() + 1}`;
        const day = `${newDate.getDate()}`;
        return `${day.length === 1 ? `0${day}` : day}.${month.length === 1 ? `0${month}` : month}.${newDate.getFullYear()}`;
    };

    const toggleImgID = () => setImgID(prevID => (prevID === '1' ? '2' : '1'));
    const shouldShowSwapButton = !(imgUrl.startsWith('id_') && parseInt(imgUrl.replace('id_', ''), 10) >= 1 && parseInt(imgUrl.replace('id_', ''), 10) <= 12);

    const parsedHpStun = useMemo<number[]>(() => {
        const rawHpStun = hpStun as any;
        if (Array.isArray(rawHpStun)) return rawHpStun.map((v: any) => Number(v));
        if (typeof rawHpStun === 'string') {
            return rawHpStun.split('|').map((v: string) => Number(v.trim())).filter((v: number) => !isNaN(v));
        }
        return [];
    }, [hpStun]);

    return (
        <section className={'entityFullInfo-entity'}>
            <article className={"entityFullInfo-img"}>
                <div className="entityFullInfo-rarity">{rarityStyled}</div>
                <img className="entityFullInfo-sinner" src={`${process.env.PUBLIC_URL}/images/sinners-icons/${sinner}.webp`} alt={`${sinner}`} />
                <div className={"shadow"}>
                     <img src={getImagePath()} alt={`${imgUrl}`} />
                </div>
                {shouldShowSwapButton && (
                    <button onClick={toggleImgID} className="image-swap-button">
                        {t(isSwitched ? "EntityFullInfoIdentity.switchImage2" : "EntityFullInfoIdentity.switchImage1")}
                    </button>
                )}
                <div className="entityFullInfo-tier-container" style={{ cursor: 'default' }}>
                    {tiers.map((tier, index) => (
                        <div key={index} className={`entityFullInfo-tier entityFullInfo-tier-${tier} tooltip-container`}>
                            <div className="tier-vote-wrapper">
                                {isReviewer ? (
                                    <>
                                        <button className="vote-btn minus" onClick={(e) => { e.stopPropagation(); handleVote(-1); }}>-</button>
                                        <span className="tier-text">{tier}{index === 0 && ` / ${avgRating}`}</span>
                                        <button className="vote-btn plus" onClick={(e) => { e.stopPropagation(); handleVote(1); }}>+</button>
                                        <div className="entityFullInfo-tooltip">{myRank}</div>
                                    </>
                                ) : (
                                    <span className="tier-text">{tier}</span>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            </article>

            <div className={'entityFullInfo-stats-container'}>
                <article className={"entityFullInfo-stats"} onClick={isAdmin ? openAdminPanel : undefined} style={{ cursor: isAdmin ? 'pointer' : 'default' }}>
                    <h2>{t("EntityFullInfoIdentity.info")}</h2>
                    {!season[1] ?
                        <div className={`entityFullInfo-season entityFullInfo-season-${season[0][0] === 'w' ? 'w' : season[0].replace(/^i-/, 's-')}`}>
                            {t(`EntityFullInfoIdentity.season.${season}`)}
                        </div> :
                        <div className={`entityFullInfo-season entityFullInfo-season-${season[1][0] === 'w' ? 'w' : season[0].replace(/^i-/, 's-')}`}>
                            {t(`EntityFullInfoIdentity.season.${season[0]}`)} [{t(`EntityFullInfoIdentity.season.${season[1]}`)}]
                        </div>
                    }
                    <div className={"entityFullInfo-release"}>
                         {t('EntityFullInfoIdentity.release')} &nbsp;
                        <span className="date">{formateDate(releaseDate)}</span>
                    </div>
                </article>

                {fuseStatuses && (
                    <article className={"entityFullInfo-stats"}>
                        <h2>{t("EntityFullInfoIdentity.statuses")}</h2>
                        <ul className='statuses-list'>
                            {filteredStatusKeys.map((s, index) => {
                                const statusItem = statuses.find(st => st.id === s);
                                if (!statusItem) return null;
                                const descriptionKey = `description${i18n.language.toUpperCase()}` as keyof typeof statusItem;
                                const description = statusItem?.[descriptionKey] as string || '';
                                const nameKey = `name${i18n.language.toUpperCase()}` as keyof typeof statusItem;
                                const name = statusItem?.[nameKey] as string || '';
                                const imgHTML = <img src={`${process.env.PUBLIC_URL}/images/tags/${s}.webp`} alt={`${s}`} />;
                                const mobileStatusHTML = <TooltipMobile text={description} header={name} image={imgHTML} />;
                                return (
                                    <li key={index} onClick={() => setMobileModalTrigger(dispatch, mobileStatusHTML)} className='tooltip-container '>
                                        {imgHTML}
                                        <span className='entityFullInfo-tooltip'>{t("SkillCoinDescription.clickToSeeDescription")}</span>
                                    </li>
                                );
                            })}
                        </ul>
                    </article>
                )}

                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoIdentity.stats")}</h2>
                    <ul>
                        <li><img src={`${process.env.PUBLIC_URL}/images/general/hp.webp`} alt={`${imgUrl}`} />{hp}</li>
                        <li><img src={`${process.env.PUBLIC_URL}/images/general/speed.webp`} alt={`${imgUrl}`} />{speed}</li>
                        <li><img src={`${process.env.PUBLIC_URL}/images/general/defense1.webp`} alt={`${imgUrl}`} />{defLevelValue}</li>
                    </ul>
                </article>

                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoIdentity.res")}</h2>
                    <ul>
                        <li className={`resistance--${slash}`}><img src={`${process.env.PUBLIC_URL}/images/general/slash.webp`} alt={`${imgUrl}`} />{resMap[slash]}</li>
                        <li className={`resistance--${pierce}`}><img src={`${process.env.PUBLIC_URL}/images/general/pierce.webp`} alt={`${imgUrl}`} />{resMap[pierce]}</li>
                        <li className={`resistance--${blunt}`}><img src={`${process.env.PUBLIC_URL}/images/general/blunt.webp`} alt={`${imgUrl}`} />{resMap[blunt]}</li>
                    </ul>
                </article>

                <article className={"entityFullInfo-stats"}>
                    <h2>{t("EntityFullInfoIdentity.stagger")}</h2>
                    <ul className='staggers'>
                        {parsedHpStun.map((e: number, index: number) => (
                            <li key={index}><span>{(hp * e / 100).toFixed()} ({e}<span className='perCent-special-font'>%</span>)</span></li>
                        ))}
                    </ul>
                </article>
                
                <article className={"entityFullInfo-stats"}>
                    <h2 className="s1yn-ego-container">{t("EntityFullInfoIdentity.synEGO")}</h2>
                    <div className="syn-ego-container">
                        {synEGO?.split(",").filter(Boolean).map((v: string, index: number) => (
                            <div key={index} className="syn-ego-item-wrapper">
                                <SkillCoinDescription description={`&${v.trim()}&`} />
                            </div>
                        ))}
                    </div>
                </article>
            </div>

            {isAdminPanelOpen && (
                <div className="admin-modal-overlay">
                    <div className="admin-modal">
                        <div className="admin-modal-header">
                            Панель управления сущностью: {identity.nameRU || identity.imgUrl}
                        </div>
                        <div className="admin-modal-body">
                            <div className="admin-modal-sidebar">
                                {ADMIN_TABS.map((tab: AdminTab) => (
                                    <button
                                        key={tab.id}
                                        className={`admin-sidebar-item ${activeTab === tab.id ? 'active' : ''}`}
                                        onClick={() => setActiveTab(tab.id)}
                                    >
                                        {tab.title}
                                    </button>
                                ))}
                            </div>
                            
                            <div className="admin-modal-content">
                                {ADMIN_TABS.find((t: AdminTab) => t.id === activeTab)?.fields.map((field: AdminField) => (
                                    <div key={field.key} className="admin-field-group">
                                        <label>{field.label}</label>
                                        {/* ИСПРАВЛЕНО: Добавлена проверка на descriptionCoin для рендера textarea вместо input */}
                                        {field.type === 'text' ? (
                                            <textarea
                                                value={adminFormData[field.key] || ''}
                                                onChange={(e) => handleFormChange(field.key, e.target.value)}
                                            />
                                        ) : (
                                            <input
                                                type={field.type === 'number' ? 'number' : 'text'}
                                                value={adminFormData[field.key] || ''}
                                                onChange={(e) => handleFormChange(field.key, e.target.value)}
                                            />
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                        <div className="modal-actions">
                            <button className="btn-close" onClick={() => setIsAdminPanelOpen(false)}>Отмена</button>
                            <button className="btn-save" onClick={saveAdminData}>Сохранить изменения</button>
                        </div>
                    </div>
                </div>
            )}
        </section>
    );
};
