import React, { useEffect} from "react";
import { TierList } from "../componentslimbus/tier-list/TierList";
import { useNavigate, useParams } from "react-router-dom";
import { TierListNav } from "../componentslimbus/tier-list/tier-list-nav/TierListNav";
import { FiltersSidebarLayout } from "../componentslimbus/filters/FiltersSidebarLayout";
import { CommonPageLayout } from "./CommonPageLayout";
import { LoadingPageWrapper } from "./LoadingPageWrapper";
import { useTranslation } from "react-i18next";
import { H1Component } from "../componentslimbus/h1-component/H1Component";
import { SEOHelmet } from "./SEOHelmet";
import { TierListDisclaimer } from "../componentslimbus/tier-list/tier-list-disclaimer/TierListDisclaimer";
import Analytics from "../componentslimbus/Analytics"; // Импортируем ваш компонент
import Sweepers from "../componentslimbus/Sweepers";

export const TierListPage:React.FC = () => {
    const {i18n} = useTranslation();
    const params = useParams();
    const type = params['type'] || "redirect";
    const navigate = useNavigate();
    useEffect(()=>{
        if( !(["identities","ego","statuses"].includes(type)))  navigate(`/limbus/${i18n.language}/tierlist/identities`);
    },[i18n.language, navigate, type])
    const {t} = useTranslation();
    return <CommonPageLayout>
        <Sweepers/>
            <Analytics />  {/* Вставляем компонент для GA */}
            <LoadingPageWrapper queryKeys={["ego","identities","statuses","events_list","news_list", "md-gifts","md-events","chanlog", "guides"]}>
                <SEOHelmet
                    title=""
                    description=""
                    schema={{
                        "@context": "https://schema.org",
                        "@type": "CollectionPage",
                        "name": "Limbus Company Tier List",
                        "url": `https://gll-fun.com/limbus/${i18n.language}/tierlist/${type}`
                    }}
                    />
                <H1Component header={t("TierListPage.header")}/>
                <TierListNav/>
                <TierListDisclaimer/>
                <FiltersSidebarLayout><TierList/></FiltersSidebarLayout>
            </LoadingPageWrapper>
    </CommonPageLayout> 
}
