import { Dispatch } from "react";
import { AnyAction } from "redux";

const initialState = typeof window !== "undefined"
    ? localStorage.getItem("leftMenuCollapsed") === "true"
    : false;

export const leftMenuReducer = (state = initialState,action : AnyAction):boolean =>{
    switch(action.type){
        case "LEFT_MENU_CHANGE_LAYOUT":
            return action.payload;
        default: 
            return state
    }
}

export const leftMenuChangeLayoutAction = (
    dispatch: Dispatch<AnyAction>,
    payload: boolean,
    persist = true
) => {
    if (persist) localStorage.setItem("leftMenuCollapsed", String(payload));
    dispatch({ type: "LEFT_MENU_CHANGE_LAYOUT" , payload})
}
