import React from "react";
import { Helmet } from "react-helmet-async";
import { useTranslation } from "react-i18next";
import seoContent from "../seo/seo-content.json";

interface SEOHelmetProps {
  title: string;
  description?: string;
  image?: string;
  canonical?: string;
  noindex?: boolean;
  schema?: object;
}

type SeoKey = keyof typeof seoContent;
type SeoLanguage = "ru" | "en";

const DEFAULT_IMAGE = "https://gll-fun.com/prewie/logo.png";
const SITE_NAME = "Great Limbus Library";
const SITE_URL = "https://gll-fun.com";

const getSeoKey = (pathname: string): SeoKey => {
  if (/\/identities\/?$/.test(pathname)) return "identities";
  if (/\/ego\/?$/.test(pathname)) return "ego";
  if (/\/tierlist\/ego\/?$/.test(pathname)) return "tierlistEgo";
  if (/\/tierlist\/(identities|statuses)\/?$/.test(pathname)) return "tierlistIdentities";
  if (/\/guides\/?$/.test(pathname)) return "guides";
  if (/\/statuses\/?$/.test(pathname)) return "statuses";
  if (/\/teambuilder\/?$/.test(pathname)) return "teambuilder";
  if (/\/mirror-dungeon\/themes\/?$/.test(pathname)) return "mirrorThemes";
  if (/\/mirror-dungeon\/events\/?$/.test(pathname)) return "mirrorEvents";
  if (/\/mirror-dungeon\/rest-stops\/?$/.test(pathname)) return "mirrorRestStops";
  if (/\/mirror-dungeon\/gifts\/?$/.test(pathname)) return "mirrorGifts";
  if (/\/contact\/?$/.test(pathname)) return "contact";
  if (/\/(gratitude|graditude)\/?$/.test(pathname)) return "gratitude";
  return "home";
};

const normalizePath = (pathname: string) => {
  const cleanPath = pathname.replace(/\/+$/, "");
  return cleanPath || "/";
};

export const SEOHelmet: React.FC<SEOHelmetProps> = ({
  title,
  description,
  image = DEFAULT_IMAGE,
  canonical,
  noindex = false,
  schema,
}) => {
  const { i18n } = useTranslation();
  const language: SeoLanguage = i18n.language === "ru" ? "ru" : "en";
  const pathname = typeof window !== "undefined" ? normalizePath(window.location.pathname) : "/limbus/en";
  const pageContent = seoContent[getSeoKey(pathname)][language];
  const safeTitle = title.trim() || pageContent.title;
  const safeDescription = description?.trim() || pageContent.description;
  const canonicalUrl = canonical || `${SITE_URL}${pathname}`;
  const ruUrl = `${SITE_URL}${pathname.replace(/\/limbus\/(ru|en)(?=\/|$)/, "/limbus/ru")}`;
  const enUrl = `${SITE_URL}${pathname.replace(/\/limbus\/(ru|en)(?=\/|$)/, "/limbus/en")}`;
  const locale = language === "ru" ? "ru_RU" : "en_US";
  const alternateLocale = language === "ru" ? "en_US" : "ru_RU";
  const pageSchema = {
    "@context": "https://schema.org",
    "@type": "WebPage",
    name: safeTitle,
    description: safeDescription,
    url: canonicalUrl,
    inLanguage: language,
    isPartOf: {
      "@type": "WebSite",
      name: SITE_NAME,
      url: SITE_URL,
    },
  };

  return (
    <Helmet>
      <html lang={language} />
      <title>{safeTitle}</title>
      <meta name="description" content={safeDescription} />
      <meta name="robots" content={noindex ? "noindex, nofollow" : "index, follow, max-image-preview:large"} />
      <meta name="googlebot" content={noindex ? "noindex, nofollow" : "index, follow, max-image-preview:large"} />

      <link rel="canonical" href={canonicalUrl} />
      <link rel="alternate" hrefLang="ru" href={ruUrl} />
      <link rel="alternate" hrefLang="en" href={enUrl} />
      <link rel="alternate" hrefLang="x-default" href={enUrl} />

      <meta property="og:type" content="website" />
      <meta property="og:site_name" content={SITE_NAME} />
      <meta property="og:title" content={safeTitle} />
      <meta property="og:description" content={safeDescription} />
      <meta property="og:image" content={image} />
      <meta property="og:url" content={canonicalUrl} />
      <meta property="og:locale" content={locale} />
      <meta property="og:locale:alternate" content={alternateLocale} />

      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={safeTitle} />
      <meta name="twitter:description" content={safeDescription} />
      <meta name="twitter:image" content={image} />

      <script type="application/ld+json">{JSON.stringify(pageSchema)}</script>
      {schema && <script type="application/ld+json">{JSON.stringify(schema)}</script>}
    </Helmet>
  );
};
