import { Session } from "@supabase/supabase-js";
import { useEffect, useState } from "react";
import { supabase } from "../tools/supabaseClient";

export const DISCORD_GUILD_ID = "1229849684302889063";
export const DISCORD_REVIEWER_ROLE_IDS = new Set([
  "1356325679150661712",
  "1356316522402021487",
  "1302564393887993929",
  "1229849777261248553",
  "1304083538831867924",
  "1229850737631166576",
  "1302579987442044930"
]);

let cachedToken = "";
let cachedAccess = false;
let cachedAt = 0;
let pendingCheck: Promise<boolean> | null = null;

const verifyReviewerAccess = async (session: Session | null) => {
  const provider = session?.user?.app_metadata?.provider;
  const token = session?.provider_token || "";
  if (provider !== "discord" || !token) return false;
  if (token === cachedToken && Date.now() - cachedAt < 5 * 60 * 1000) return cachedAccess;
  if (pendingCheck) return pendingCheck;

  pendingCheck = fetch(`https://discord.com/api/v10/users/@me/guilds/${DISCORD_GUILD_ID}/member`, {
    headers: { Authorization: `Bearer ${token}` }
  }).then(async response => {
    if (!response.ok) return false;
    const member = await response.json() as { roles?: string[] };
    return Array.isArray(member.roles) && member.roles.some(role => DISCORD_REVIEWER_ROLE_IDS.has(role));
  }).catch(() => false).then(access => {
    cachedToken = token;
    cachedAccess = access;
    cachedAt = Date.now();
    pendingCheck = null;
    return access;
  });

  return pendingCheck;
};

export const useReviewerAccess = () => {
  const [isReviewer, setIsReviewer] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;
    const applySession = async (session: Session | null) => {
      const access = await verifyReviewerAccess(session);
      if (!mounted) return;
      setIsReviewer(access);
      setLoading(false);
    };

    supabase.auth.getSession().then(({ data }) => applySession(data.session));
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      window.setTimeout(() => applySession(session), 0);
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  return { isReviewer, loading };
};
