import React, { useState } from "react";

type Props = {
  storageKey: string;
  kicker?: string;
  title: React.ReactNode;
  badge?: React.ReactNode;
  children: React.ReactNode;
  className?: string;
  defaultOpen?: boolean;
  collapsible?: boolean;
};

export const CollapsibleSection: React.FC<Props> = ({ storageKey, kicker, title, badge, children, className = "", defaultOpen = true, collapsible = false }) => {
  const [open, setOpen] = useState(() => {
    if (!collapsible) return true;
    const saved = localStorage.getItem(`gll-team-section-${storageKey}`);
    return saved === null ? defaultOpen : saved === "true";
  });
  const heading = (
    <>
      <span>
        {kicker && <small className="community-kicker">{kicker}</small>}
        <strong>{title}</strong>
      </span>
      <span className="team-section-meta">
        {badge !== undefined && <small className="team-section-count">{badge}</small>}
        {collapsible && <i>{open ? "−" : "+"}</i>}
      </span>
    </>
  );

  const toggle = () => setOpen(current => {
    const next = !current;
    localStorage.setItem(`gll-team-section-${storageKey}`, String(next));
    return next;
  });

  return (
    <section className={`team-collapsible-section ${open ? "is-open" : "is-closed"} ${className}`}>
      {collapsible ? <button type="button" className="team-section-heading team-section-heading--button" onClick={toggle} aria-expanded={open}>{heading}</button> : <header className="team-section-heading">{heading}</header>}
      {open && <div className="team-collapsible-body">{children}</div>}
    </section>
  );
};
