import { Session, User } from "@supabase/supabase-js";
import { useEffect, useState } from "react";
import { supabase } from "../tools/supabaseClient";

export const AUTH_RETURN_PATH_KEY = "gll-auth-return-path";

export const useAuthSession = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    let mounted = true;
    const applySession = (nextSession: Session | null) => {
      if (!mounted) return;
      setSession(nextSession);
      setLoading(false);
      if (!nextSession) return;
      const returnPath = localStorage.getItem(AUTH_RETURN_PATH_KEY);
      if (!returnPath?.startsWith("/limbus/")) return;
      localStorage.removeItem(AUTH_RETURN_PATH_KEY);
      if (window.location.pathname !== returnPath) window.location.replace(`${window.location.origin}${returnPath}`);
    };

    const oauthError = new URLSearchParams(window.location.search).get("error_description");
    if (oauthError) setError(oauthError);

    supabase.auth.getSession().then(({ data, error: sessionError }) => {
      if (sessionError && mounted) setError(sessionError.message);
      applySession(data.session);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, nextSession) => {
      applySession(nextSession);
    });
    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  return { session, user: session?.user as User | undefined, loading, error };
};
