import React, { useEffect } from "react";
import "./uptie-component.css";
import {
  UptieState,
  uptieSwitchAction,
} from "../../../store/reducers/uptie-reducer";
import { useDispatch } from "react-redux";
import { useLocation } from "react-router-dom";

interface UptieComponentProps {
  value: number;
  setValue: React.Dispatch<React.SetStateAction<number>>;
  max?: number;
  hasUptie5?: boolean;
}

export const UptieComponent: React.FC<UptieComponentProps> = ({
  value,
  setValue,
  max = 4,
  hasUptie5 = false,
}) => {
  const dispatch = useDispatch();
  const location = useLocation();

  const min = 1;

  const steps = Array.from({ length: max }, (_, i) => i + 1);

  const steps_values = ["I", "II", "III", "IV", "V"];

  const steps_offsets_X =
    max === 5
      ? [70, 60, 0, -40, -70]
      : [70, 60, -40, -70];

  // identities всегда IV
  useEffect(() => {
    const identityPathRegex = /\/identities\/id_/;

    if (identityPathRegex.test(location.pathname)) {
      const typed_value = 4 as UptieState["selectedUptie"];

      setValue(typed_value);
      uptieSwitchAction(dispatch, typed_value);
      return;
    }

    // Если есть текст после "|" -> сразу ставим Uptie V
    if (hasUptie5) {
      const typed_value = 5 as UptieState["selectedUptie"];

      setValue(typed_value);
      uptieSwitchAction(dispatch, typed_value);
    }
  }, [location.pathname, dispatch, setValue, hasUptie5]);

  // Защита от выхода за max
  useEffect(() => {
    if (value > max) {
      const typed_value = max as UptieState["selectedUptie"];

      setValue(typed_value);
      uptieSwitchAction(dispatch, typed_value);
    }
  }, [value, max, dispatch, setValue]);

  const handleValueSwitch = (
    e: React.ChangeEvent<HTMLInputElement>
  ) => {
    const newValue = Number(e.target.value);

    if (steps.includes(newValue)) {
      const typed_value = newValue as UptieState["selectedUptie"];

      setValue(typed_value);
      uptieSwitchAction(dispatch, typed_value);
    }
  };

  return (
    <div className="uptie-container">
      <span className="uptie-value-current">
        <span className="uptie-uptie-text">Uptie</span>
        {steps_values[value - 1]}
      </span>

      <div className="uptie-slider-container">
        <input
          className="uptie-range"
          type="range"
          min={min}
          max={max}
          step="1"
          value={value}
          onChange={handleValueSwitch}
          style={{
            backgroundSize: `${((value - min) / (max - min)) * 100}% 100%`,
          }}
        />

        {steps.map((step) => (
          <div
            key={step}
            style={{
              left: `${((step - min) / (max - min)) * 100}%`,
            }}
            className="slider-splitmark"
          />
        ))}

        <div className="slider-labels">
          {steps.map((step, index) => (
            <div
              key={step}
              className="slider-mark"
              style={{
                left: `${((step - min) / (max - min)) * 100}%`,
              }}
            >
              <span
                className={`slider-text ${
                  value === index + 1
                    ? "slider-text--current"
                    : ""
                }`}
                style={{
                  transform: `translateX(${steps_offsets_X[index]}%)`,
                }}
              >
                {steps_values[index]}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};