import React, { useState } from "react";
import { Provider } from "@supabase/supabase-js";
import { useTranslation } from "react-i18next";
import { AUTH_RETURN_PATH_KEY, useAuthSession } from "../../hooks/useAuthSession";
import { useReviewerAccess } from "../../hooks/useReviewerAccess";
import { supabase } from "../../tools/supabaseClient";
import { DiscordIconSVG } from "../svg/DiscordIcon";
import "./HeaderAuthButtons.css";

type Props = { inline?: boolean };

export const HeaderAuthButtons: React.FC<Props> = ({ inline = false }) => {
  const { i18n } = useTranslation();
  const ru = i18n.language === "ru";
  const { user, loading } = useAuthSession();
  const { isReviewer } = useReviewerAccess();
  const [working, setWorking] = useState<Provider | "signout" | null>(null);
  const provider = user?.app_metadata?.provider as Provider | undefined;

  const signIn = async (nextProvider: "google" | "discord") => {
    if (provider === nextProvider) {
      setWorking("signout");
      await supabase.auth.signOut();
      setWorking(null);
      return;
    }

    setWorking(nextProvider);
    localStorage.setItem(AUTH_RETURN_PATH_KEY, window.location.pathname);
    const { error } = await supabase.auth.signInWithOAuth({
      provider: nextProvider,
      options: {
        redirectTo: `${window.location.origin}${window.location.pathname}`,
        scopes: nextProvider === "discord" ? "identify email guilds.members.read" : undefined,
        queryParams: nextProvider === "discord" ? { prompt: "consent" } : undefined
      }
    });
    if (error) {
      localStorage.removeItem(AUTH_RETURN_PATH_KEY);
      setWorking(null);
    }
  };

  const title = (nextProvider: "google" | "discord") => {
    if (provider === nextProvider) return ru ? "Выйти из аккаунта" : "Sign out";
    if (nextProvider === "discord") return ru ? "Войти через Discord" : "Sign in with Discord";
    return ru ? "Войти через Google" : "Sign in with Google";
  };

  return (
    <div className={`compact-auth-buttons ${inline ? "inline" : "header"}`} aria-label={ru ? "Вход в аккаунт" : "Account sign in"}>
      <button
        type="button"
        className={`compact-auth-button google ${provider === "google" ? "active" : ""}`}
        onClick={() => signIn("google")}
        disabled={loading || working !== null}
        title={title("google")}
        aria-label={title("google")}
      >
        <span>G</span>
      </button>
      <button
        type="button"
        className={`compact-auth-button discord ${provider === "discord" ? "active" : ""} ${isReviewer ? "reviewer" : ""}`}
        onClick={() => signIn("discord")}
        disabled={loading || working !== null}
        title={title("discord")}
        aria-label={title("discord")}
      >
        <DiscordIconSVG />
      </button>
    </div>
  );
};
