import { parseEntityTraits } from "../../entity-full-info/traits";

export type TeamStatusOption = {
  value: string;
  label: string;
  search: string;
};

export const getTeamStatusOptions = (statuses: any[], ru: boolean, identities: any[] = []): TeamStatusOption[] => {
  const unique = new Map<string, TeamStatusOption>();
  statuses.forEach(status => {
    const value = String(status.id || status.nameEN || status.nameRU || "").trim();
    if (!value || unique.has(value)) return;
    const nameRu = String(status.nameRU || "").trim();
    const nameEn = String(status.nameEN || "").trim();
    unique.set(value, {
      value,
      label: (ru ? nameRu || nameEn : nameEn || nameRu) || value,
      search: `${value} ${nameRu} ${nameEn}`.toLocaleLowerCase()
    });
  });
  identities.forEach(identity => {
    parseEntityTraits(identity.traits)
      .filter(trait => !trait.negated)
      .forEach(trait => {
        const value = `trait:${trait.name}`;
        if (unique.has(value)) return;
        unique.set(value, {
          value,
          label: trait.name,
          search: `${trait.name} trait ${ru ? "трейт" : ""}`.toLocaleLowerCase()
        });
      });
  });
  return Array.from(unique.values());
};
