import React, { useEffect, useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { User } from "@supabase/supabase-js";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { SINNER_ORDER } from "../../../store/reducers/tb-reducer";
import { supabase } from "../../../tools/supabaseClient";
import { encodeFormationCode } from "../tb-slots/tb-utils";
import { CollapsibleSection } from "./CollapsibleSection";
import { StatusAutocomplete } from "./StatusAutocomplete";
import { BattleOrderSelector } from "./BattleOrderSelector";
import { getTeamStatusOptions } from "./status-utils";
import { TEAM_CONTENT_TYPES, TEAM_STATUS_COLORS, TeamContentType, applyBattleOrder } from "./team-types";

type Props = { user: User; onSaved: () => void };

type TeamPresetDraft = {
  titleRu: string;
  titleEn: string;
  descriptionRu: string;
  descriptionEn: string;
  youtubeUrl: string;
  isPublic: boolean;
  contentType: TeamContentType;
  battleOrders: Record<number, number>;
  selectedStatuses: string[];
  mainStatus: string;
  backgroundStatus: string;
};

const loadDraft = (key: string): Partial<TeamPresetDraft> => {
  try {
    return JSON.parse(localStorage.getItem(key) || "{}") as Partial<TeamPresetDraft>;
  } catch {
    return {};
  }
};

export const TeamPresetForm: React.FC<Props> = ({ user, onSaved }) => {
  const { i18n } = useTranslation();
  const ru = i18n.language === "ru";
  const { slots } = useTypedSelector(store => store.tbReducer);
  const queryClient = useQueryClient();
  const draftKey = `gll-team-preset-draft:${user.id}`;
  const [initialDraft] = useState(() => loadDraft(draftKey));
  const [titleRu, setTitleRu] = useState(initialDraft.titleRu || "");
  const [titleEn, setTitleEn] = useState(initialDraft.titleEn || "");
  const [descriptionRu, setDescriptionRu] = useState(initialDraft.descriptionRu || "");
  const [descriptionEn, setDescriptionEn] = useState(initialDraft.descriptionEn || "");
  const [youtubeUrl, setYoutubeUrl] = useState(initialDraft.youtubeUrl || "");
  const [isPublic, setIsPublic] = useState(typeof initialDraft.isPublic === "boolean" ? initialDraft.isPublic : true);
  const [contentType, setContentType] = useState<TeamContentType>(TEAM_CONTENT_TYPES.some(option => option.value === initialDraft.contentType) ? initialDraft.contentType! : "mirror_dungeon");
  const [battleOrders, setBattleOrders] = useState<Record<number, number>>(initialDraft.battleOrders || {});
  const [selectedStatuses, setSelectedStatuses] = useState<string[]>(Array.isArray(initialDraft.selectedStatuses) ? initialDraft.selectedStatuses : []);
  const [mainStatus, setMainStatus] = useState(initialDraft.mainStatus || "");
  const [backgroundStatus, setBackgroundStatus] = useState(initialDraft.backgroundStatus || "");
  const [saving, setSaving] = useState(false);
  const [notice, setNotice] = useState<{ error?: boolean; text: string } | null>(null);

  useEffect(() => {
    const draft: TeamPresetDraft = {
      titleRu,
      titleEn,
      descriptionRu,
      descriptionEn,
      youtubeUrl,
      isPublic,
      contentType,
      battleOrders,
      selectedStatuses,
      mainStatus,
      backgroundStatus
    };
    try {
      localStorage.setItem(draftKey, JSON.stringify(draft));
    } catch {
      // Draft persistence must not block editing when browser storage is unavailable.
    }
  }, [backgroundStatus, battleOrders, contentType, descriptionEn, descriptionRu, draftKey, isPublic, mainStatus, selectedStatuses, titleEn, titleRu, youtubeUrl]);

  const statusOptions = useMemo(() => {
    const statuses = queryClient.getQueryData<any[]>("statuses") || [];
    const identities = queryClient.getQueryData<any[]>("identities") || [];
    return getTeamStatusOptions(statuses, ru, identities);
  }, [queryClient, ru]);

  const changeStatuses = (next: string[]) => {
    setSelectedStatuses(next);
    if (!next.includes(mainStatus)) setMainStatus(next[0] || "");
    if (!next.includes(backgroundStatus)) setBackgroundStatus("");
  };

  const statusLabel = (value: string) => statusOptions.find(option => option.value === value)?.label || value;

  const submit = async (event: React.FormEvent) => {
    event.preventDefault();
    if (!slots.some(slot => slot.identity)) {
      setNotice({ error: true, text: ru ? "Добавьте хотя бы одну личность." : "Add at least one Identity." });
      return;
    }
    const combatCount = slots.filter(slot => slot.identity && slot.role !== "support").length;
    if (isPublic && combatCount > 7) {
      setNotice({ error: true, text: ru ? "В публичной команде может быть не более 7 бойцов на поле." : "A public team may have no more than 7 units on the field." });
      return;
    }
    if (!(titleRu.trim() || titleEn.trim())) {
      setNotice({ error: true, text: ru ? "Заполните название хотя бы на одном языке." : "Add a title in at least one language." });
      return;
    }
    setSaving(true);
    setNotice(null);
    try {
      const orderedSlots = applyBattleOrder(slots, battleOrders);
      const teamCode = await encodeFormationCode(orderedSlots, queryClient);
      const lineup = orderedSlots.map((slot, index) => ({
        sinner: SINNER_ORDER[index],
        role: slot.role === "support" ? "support" : "combat",
        battle_order: slot.role === "support" ? (battleOrders[index] || null) : slot.teamCodeSlotType,
        identity: slot.identity ? {
          imgUrl: slot.identity.imgUrl,
          nameRU: (slot.identity as any).nameRU || (slot.identity as any).nameRu,
          nameEN: (slot.identity as any).nameEN || (slot.identity as any).nameEn
        } : null,
        ego: Object.fromEntries(Object.entries(slot.ego || {}).filter(([, ego]) => ego).map(([rarity, ego]: [string, any]) => [rarity, ego.imgUrl]))
      }));
      const { error } = await supabase.from("team_presets").insert({
        user_id: user.id,
        title: titleRu.trim() || titleEn.trim(),
        title_ru: titleRu.trim() || null,
        title_en: titleEn.trim() || null,
        description: descriptionRu.trim() ? descriptionRu : descriptionEn,
        description_ru: descriptionRu.trim() ? descriptionRu : null,
        description_en: descriptionEn.trim() ? descriptionEn : null,
        is_public: isPublic,
        content_type: contentType,
        moderation_status: isPublic ? "pending" : "private",
        youtube_url: youtubeUrl || null,
        team_code: teamCode,
        lineup,
        slot_roles: lineup.map(slot => slot.role),
        statuses: selectedStatuses,
        main_status: mainStatus || null,
        background_status: backgroundStatus || null
      });
      if (error) throw error;
      setTitleRu("");
      setTitleEn("");
      setDescriptionRu("");
      setDescriptionEn("");
      setYoutubeUrl("");
      setSelectedStatuses([]);
      setMainStatus("");
      setBackgroundStatus("");
      setBattleOrders({});
      setNotice({ text: isPublic ? (ru ? "Команда отправлена на проверку." : "Team submitted for review.") : (ru ? "Приватная команда сохранена." : "Private team saved.") });
      onSaved();
    } catch (error: any) {
      setNotice({ error: true, text: error?.message || (ru ? "Не удалось сохранить команду." : "Could not save the team.") });
    } finally {
      setSaving(false);
    }
  };

  return (
    <CollapsibleSection storageKey="submit" kicker="NEW PRESET" title={ru ? "Сохранить текущую команду" : "Save current team"} className="team-preset-shell" collapsible>
    <form className="team-preset-form" onSubmit={submit}>
      <div className="team-preset-fields">
        <label><span>Название RU</span><input value={titleRu} onChange={event => setTitleRu(event.target.value)} maxLength={120} /></label>
        <label><span>Title EN</span><input value={titleEn} onChange={event => setTitleEn(event.target.value)} maxLength={120} /></label>
        <label><span>Описание RU</span><textarea value={descriptionRu} onChange={event => setDescriptionRu(event.target.value)} maxLength={5000} rows={5} /></label>
        <label><span>Description EN</span><textarea value={descriptionEn} onChange={event => setDescriptionEn(event.target.value)} maxLength={5000} rows={5} /></label>
        <label><span>{ru ? "Тип контента" : "Content type"}</span><select value={contentType} onChange={event => setContentType(event.target.value as TeamContentType)}>{TEAM_CONTENT_TYPES.map(option => <option value={option.value} key={option.value}>{ru ? option.ru : option.en}</option>)}</select></label>
        <label className="team-visibility-field"><span>{ru ? "Доступ" : "Visibility"}</span><select value={isPublic ? "public" : "private"} onChange={event => setIsPublic(event.target.value === "public")}><option value="public">{ru ? "Публичная — отправить на модерацию" : "Public — submit for review"}</option><option value="private">{ru ? "Приватная — только для меня" : "Private — only me"}</option></select></label>
        <BattleOrderSelector slots={slots} orders={battleOrders} onChange={setBattleOrders} ru={ru} />
        <div className="team-preset-field--wide team-status-field">
          <div className="team-status-field-title"><span>{ru ? "Статусы и трейты команды" : "Team statuses and traits"}</span><strong>{mainStatus ? `${ru ? "Основной" : "Main"}: ${statusLabel(mainStatus)}` : (ru ? "Основной не выбран" : "No main tag")}</strong></div>
          <StatusAutocomplete
            options={statusOptions}
            selected={selectedStatuses}
            onChange={changeStatuses}
            placeholder={ru ? "Статус или трейт: горение, Fixer…" : "Status or trait: burn, Fixer…"}
            mainStatus={mainStatus}
            onMainChange={setMainStatus}
            noResults={ru ? "Подходящих статусов или трейтов нет" : "No matching statuses or traits"}
            mainTitle={ru ? "Сделать основным" : "Set as main"}
          />
          <small>{ru ? "Выберите до 8 статусов или трейтов. Звезда отмечает основной тег." : "Select up to 8 statuses or traits. The star marks the main tag."}</small>
          <div className="team-card-accent-field">
            <span>{ru ? "Фоновый акцент" : "Background accent"}</span>
            <button type="button" className={!backgroundStatus ? "is-active" : ""} onClick={() => setBackgroundStatus("")}>{ru ? "Без цвета" : "No color"}</button>
            {selectedStatuses.filter(status => TEAM_STATUS_COLORS[status]).map(status => <button type="button" className={backgroundStatus === status ? "is-active" : ""} style={{ "--status-choice-rgb": TEAM_STATUS_COLORS[status] } as React.CSSProperties} onClick={() => setBackgroundStatus(status)} key={status}><i />{statusLabel(status)}</button>)}
          </div>
        </div>
        <label className="team-preset-field--wide"><span>{ru ? "YouTube-ссылка (необязательно)" : "YouTube link (optional)"}</span><input type="url" value={youtubeUrl} onChange={event => setYoutubeUrl(event.target.value)} placeholder="https://youtu.be/…" /></label>
        {isPublic && <aside className="team-publishing-rules team-preset-field--wide"><strong>{ru ? "Правила для одобрения команды" : "Rules for team to be approved"}</strong><ol>{(ru ? [
          "Описание, название и прикреплённое видео не должны содержать оскорблений, ругательств, NSFW-контента и тому подобного.",
          "Не стоит публиковать совсем бессмысленные команды со случайными идентичностями.",
          "Публикуйте команды только в том случае, если вы правда желаете ими поделиться. Некоторым командам стоит остаться только на вашем аккаунте."
        ] : [
          "Team name, description and embedded video must not contain any heavy language, slurs, NSFW-content and so on.",
          "You shouldn't post teams that make no sense with random identities.",
          "Post teams only if you really want to share them. Some teams should remain on your own account."
        ]).map(rule => <li key={rule}>{rule}</li>)}</ol></aside>}
      </div>
      <footer><small>{isPublic ? (ru ? "Публичная команда появится после одобрения." : "The public team appears after approval.") : (ru ? "Приватную команду видите только вы." : "Only you can see a private team.")}</small><button type="submit" disabled={saving}>{saving ? (ru ? "Сохранение…" : "Saving…") : isPublic ? (ru ? "На модерацию" : "Submit for review") : (ru ? "Сохранить приватно" : "Save privately")}</button></footer>
      {notice && <div className={notice.error ? "community-error" : "community-success"}>{notice.text}</div>}
    </form>
    </CollapsibleSection>
  );
};
