import React, { useEffect} from "react";
import { useNavigate, useParams } from "react-router-dom";
import { CommonPageLayout } from "./CommonPageLayout";
import { LoadingPageWrapper } from "./LoadingPageWrapper";
import { useTranslation } from "react-i18next";
import { H1Component } from "../componentslimbus/h1-component/H1Component";
import { MirrorDungeonNav } from "../componentslimbus/mirror-dungeon/nav/MirrorDungeonNav";
import { MDRouteHandler } from "../componentslimbus/mirror-dungeon/route-type-handler/MDRouteHandler";
import Analytics from "../componentslimbus/Analytics"; // Импортируем ваш компонент
import { SEOHelmet } from "./SEOHelmet";
import Sweepers from "../componentslimbus/Sweepers";
import { useReviewerAccess } from "../hooks/useReviewerAccess";

export const MirrorDungeonPage:React.FC = () => {
    const {i18n} = useTranslation();
    const params = useParams();
    const type = params['type'] || "redirect";
    const navigate = useNavigate();
    const { isReviewer, loading: reviewerLoading } = useReviewerAccess();
    useEffect(()=>{
        if (reviewerLoading) return;
        if (type === "themes" && !isReviewer) {
            navigate(`/limbus/${i18n.language}/mirror-dungeon/events`, { replace: true });
            return;
        }
        if (!(isReviewer ? ["themes", "rest-stops", "gifts", "events"] : ["rest-stops", "gifts", "events"]).includes(type)) {
            navigate(`/limbus/${i18n.language}/mirror-dungeon/events`, { replace: true });
        }
    },[i18n.language, isReviewer, navigate, reviewerLoading, type])
    const {t} = useTranslation();
    if (type === "themes" && reviewerLoading) return null;
    return <CommonPageLayout>
        <Sweepers/>
            <Analytics />  {/* Вставляем компонент для GA */}
            <SEOHelmet
                title=""
                description=""
                />

            <LoadingPageWrapper queryKeys={["ego","identities","statuses","events_list","news_list", "md-gifts","md-events","chanlog", "themes"]}>
                
                <H1Component header={t("MirrorDungeonPage.header")}/>
                <MirrorDungeonNav/>
                <MDRouteHandler/>
            </LoadingPageWrapper>
    </CommonPageLayout> 
}
