import React, { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { H1Component } from "../componentslimbus/h1-component/H1Component";
import { TbSins } from "../componentslimbus/team-builder/tb-sins/TbSins";
import { TbResists } from "../componentslimbus/team-builder/tb-resists/TbResists";
import { TbSlots } from "../componentslimbus/team-builder/tb-slots/TbSlots";
import { TbSynergy } from "../componentslimbus/team-builder/tb-synergy/TbSynergy";
import { TbTags } from "../componentslimbus/team-builder/tb-tags/TbTags";
import { TbResonance } from "../componentslimbus/team-builder/tb-resonance/TbResonance";
import { tbLoadStoredDataAction } from "../store/reducers/tb-reducer";
import { CommonPageLayout } from "./CommonPageLayout";
import { LoadingPageWrapper } from "./LoadingPageWrapper";
import { SEOHelmet } from "./SEOHelmet";
import Analytics from "../componentslimbus/Analytics"; // Импортируем ваш компонент
import Sweepers from "../componentslimbus/Sweepers";
import { useAuthSession } from "../hooks/useAuthSession";
import { TeamAccountPanel } from "../componentslimbus/team-builder/community/TeamAccountPanel";
import { TeamPresetForm } from "../componentslimbus/team-builder/community/TeamPresetForm";
import { CommunityTeams } from "../componentslimbus/team-builder/community/CommunityTeams";
import { CollapsibleSection } from "../componentslimbus/team-builder/community/CollapsibleSection";
import "./TeamBuilderPage.css";

export const TeamBuilderPage:React.FC = () => {
    const {t} = useTranslation();
    const dispatch = useDispatch();
    const { user, loading: authLoading, error: authError } = useAuthSession();
    const [teamsRefreshKey, setTeamsRefreshKey] = useState(0);

    useEffect(() => {
        tbLoadStoredDataAction(dispatch);
    }, [dispatch]);

    return  <CommonPageLayout >
        <Sweepers/>
            <Analytics />  {/* Вставляем компонент для GA */}
        <LoadingPageWrapper queryKeys={["ego","identities","statuses","events_list","news_list", "md-gifts","md-events","chanlog", "guides"]}>
                <SEOHelmet
                title=""
                description=""
                />

                <H1Component header={t("TeamBuilderPage.header")}/>
                <TeamAccountPanel user={user} loading={authLoading} sessionError={authError} />
                <CollapsibleSection storageKey="builder" kicker="TEAM BUILDER" title={t("TeamBuilderPage.header")} className="team-builder-panel">
                <div className="team-builder-workspace">
                    <div className="team-builder-main-column">
                        <TbSlots/>
                        <div className="team-builder-summary-row">
                            <TbSins/>
                            <TbResists/>
                            <TbResonance/>
                        </div>
                    </div>
                    <TbSynergy/>
                </div>
                <TbTags/>
                </CollapsibleSection>
                {user && <TeamPresetForm user={user} onSaved={() => setTeamsRefreshKey(value => value + 1)} />}
                <CommunityTeams user={user} refreshKey={teamsRefreshKey} />
        </LoadingPageWrapper>
    </CommonPageLayout> 
}
